# Search hadith database for approximate matches to the original span
def best_hadith_matches(query, topn=10):
    items = []
    for idx, e in enumerate(hadith_data):
        text = e.get('Matn') or e.get('hadithTxt') or ''
        if not text:
            continue
        score = similarity_score(query, text)
        if score > 0.6:
            items.append((score, idx, text))
    items.sort(key=lambda x: -x[0])
    return items[:topn]

